#![no_std]
#![no_main]

use aya_bpf::{macros::classifier, programs::TcContext, BpfContext};
use aya_log_ebpf::info;

#[classifier]
pub fn interceptor(ctx: TcContext) -> i32 {
    match try_interceptor(ctx) {
        Ok(ret) => ret,
        Err(ret) => ret,
    }
}

fn try_interceptor(ctx: TcContext) -> Result<i32, i32> {
    let pid = ctx.pid();
    info!(&ctx, "received a packet");
    Ok(0)
}

#[panic_handler]
fn panic(_info: &core::panic::PanicInfo) -> ! {
    unsafe { core::hint::unreachable_unchecked() }
}
